var isVisible = StelObjectMgr.getFlagSelectedObjectPointer();
core.debug('Selected object pointer visible: ' + isVisible);

if(!isVisible) {
    StelObjectMgr.setFlagSelectedObjectPointer(true);
    core.debug('Selection pointer enabled');
}

// Enable the selection pointer
StelObjectMgr.setFlagSelectedObjectPointer(true);

// Disable the selection pointer
StelObjectMgr.setFlagSelectedObjectPointer(false);

// Toggle the pointer visibility
var current = StelObjectMgr.getFlagSelectedObjectPointer();
StelObjectMgr.setFlagSelectedObjectPointer(!current);

var Script = 33554432;
var DebugAid = 67108864;

// Add a simple script message
StelObjectMgr.addToExtraInfoString(Script, "My script is running successfully<br/>");

// Add debugging information with HTML formatting
StelObjectMgr.addToExtraInfoString(DebugAid, "<span style='color:#ffaa00;'>DEBUG: Custom calculation</span><br/>");

// Add to multiple flag groups
StelObjectMgr.addToExtraInfoString(Script | DebugAid, "This appears in both sections<br/>");

// Add astronomical calculation results
var altitude = 45.5;
StelObjectMgr.addToExtraInfoString(2048, "Custom altitude: " + altitude + "°<br/>");

// Clear messages later
StelObjectMgr.removeExtraInfoStrings(Script);

var Script = 33554432;
var DebugAid = 67108864;

// Set a debug message (replaces any existing debug messages)
StelObjectMgr.setExtraInfoString(DebugAid, "<span style='color:#ff0000;'>[ERROR] Calculation failed</span><br/>");

// Set script info
StelObjectMgr.setExtraInfoString(Script, "<b>Custom Data:</b> Temperature: 25°C<br/>");

// Clear all script messages
StelObjectMgr.setExtraInfoString(Script, "");

// Update a status message
StelObjectMgr.setExtraInfoString(Script, "Processing... " + step + " of " + total);

var Script = 33554432;
var DebugAid = 67108864;

// Remove all script messages only
StelObjectMgr.removeExtraInfoStrings(Script);

// Remove all debug messages only
StelObjectMgr.removeExtraInfoStrings(DebugAid);

// Remove both script AND debug messages
StelObjectMgr.removeExtraInfoStrings(Script | DebugAid);

// Remove everything (all flag types)
var AllFlags = 536870911;
StelObjectMgr.removeExtraInfoStrings(AllFlags);
